workflow.sql:
select id, tenant, name, email, status
from users
where tenant = @tenantCode
@if keyword != "" {
  and (name like '%' || @keyword || '%' or email like '%' || @keyword || '%')
}
@if len(statusList) > 0 {
  and status in (@statusList)
}
order by @=sortColumn @=sortDirection
limit @limitNum
offset @offsetNum
